internal sealed interface AppDocumentEditorAvailability {
    data class Ready(val draft: NativeUiDocumentDraft) : AppDocumentEditorAvailability
    data class Blank(val suggestion: NativeUiDocumentDraft) : AppDocumentEditorAvailability
    data class RawFallback(val message: String) : AppDocumentEditorAvailability
}

