internal fun resolveAppDocumentEditorAvailability(
    rawJson: String,
    requiredTabRouteIds: List<String>,
    homeTabId: String,
): AppDocumentEditorAvailability {
    val candidate = rawJson.trim()
    if (candidate.isBlank()) {
        return AppDocumentEditorAvailability.Blank(
            suggestion = createSuggestedDocumentDraft(requiredTabRouteIds, homeTabId)
        )
    }
    return runCatching {
        AppDocumentEditorAvailability.Ready(parseDocumentDraft(candidate))
    }.getOrElse { exception ->
        AppDocumentEditorAvailability.RawFallback(
            message = exception.message ?: "This app document uses fields the guided editor does not support yet."
        )
    }
}

internal fun encodeDocumentDraft(draft: NativeUiDocumentDraft): String =
    guidedEditorJson.encodeToString(
        JsonElement.serializer(),
        buildJsonObject {
            put("id", JsonPrimitive(draft.id))
            put("version", JsonPrimitive(draft.version))
            put("rootPageId", JsonPrimitive(draft.rootPageId))
            put(
                "pages",
                JsonArray(draft.pages.map(::pageToJson))
            )
        },
    )

private fun pageToJson(page: NativeUiPageDraft): JsonObject =
    buildJsonObject {
        put("id", JsonPrimitive(page.id))
        if (page.slug.isNotBlank()) put("slug", JsonPrimitive(page.slug))
        if (page.title.isNotBlank()) put("title", JsonPrimitive(page.title))
        put("blocks", JsonArray(page.blocks.map(::blockToJson)))
    }

private fun blockToJson(block: NativeUiBlockDraft): JsonObject =
    when (block) {
        is NativeUiTextBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("text", JsonPrimitive(block.text))
            put("variant", JsonPrimitive(block.variant.wireValue))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            block.colorRole?.let { put("colorRole", JsonPrimitive(it.wireValue)) }
        }

        is NativeUiImageBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("url", JsonPrimitive(block.url))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            block.contentDescription.ifNotBlank { put("contentDescription", JsonPrimitive(it)) }
            block.aspectRatio.toFloatOrNull()?.let { put("aspectRatio", JsonPrimitive(it)) }
        }

        is NativeUiButtonBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("label", JsonPrimitive(block.label))
            put("style", JsonPrimitive(block.style.wireValue))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            actionToJson(block.action)?.let { put("action", it) }
            block.containerColorRole?.let { put("containerColorRole", JsonPrimitive(it.wireValue)) }
            block.contentColorRole?.let { put("contentColorRole", JsonPrimitive(it.wireValue)) }
            block.borderColorRole?.let { put("borderColorRole", JsonPrimitive(it.wireValue)) }
        }

        is NativeUiSpacerBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("heightDp", JsonPrimitive(block.heightDp))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
        }

        is NativeUiSectionBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            block.title.ifNotBlank { put("title", JsonPrimitive(it)) }
            put("blocks", JsonArray(block.blocks.map(::blockToJson)))
        }

        is NativeUiCardBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("style", JsonPrimitive(block.style.wireValue))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            block.title.ifNotBlank { put("title", JsonPrimitive(it)) }
            block.body.ifNotBlank { put("body", JsonPrimitive(it)) }
            actionToJson(block.action)?.let { put("action", it) }
            if (block.blocks.isNotEmpty()) put("blocks", JsonArray(block.blocks.map(::blockToJson)))
            block.containerColorRole?.let { put("containerColorRole", JsonPrimitive(it.wireValue)) }
            block.contentColorRole?.let { put("contentColorRole", JsonPrimitive(it.wireValue)) }
            block.borderColorRole?.let { put("borderColorRole", JsonPrimitive(it.wireValue)) }
        }

        is NativeUiListBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            put(
                "items",
                buildJsonArray {
                    block.items.forEach { item ->
                        add(
                            buildJsonObject {
                                put("title", JsonPrimitive(item.title))
                                item.subtitle.ifNotBlank { put("subtitle", JsonPrimitive(it)) }
                                item.overline.ifNotBlank { put("overline", JsonPrimitive(it)) }
                                actionToJson(item.action)?.let { put("action", it) }
                            }
                        )
                    }
                },
            )
        }

        is NativeUiEventCardBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("title", JsonPrimitive(block.title))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            block.subtitle.ifNotBlank { put("subtitle", JsonPrimitive(it)) }
            block.dateLabel.ifNotBlank { put("dateLabel", JsonPrimitive(it)) }
            block.locationLabel.ifNotBlank { put("locationLabel", JsonPrimitive(it)) }
            block.imageUrl.ifNotBlank { put("imageUrl", JsonPrimitive(it)) }
            actionToJson(block.action)?.let { put("action", it) }
        }

        is NativeUiTicketCardBlockDraft -> buildJsonObject {
            put("type", JsonPrimitive(block.type.wireValue))
            put("title", JsonPrimitive(block.title))
            block.id.ifNotBlank { put("id", JsonPrimitive(it)) }
            block.subtitle.ifNotBlank { put("subtitle", JsonPrimitive(it)) }
            block.status.ifNotBlank { put("status", JsonPrimitive(it)) }
            block.holderName.ifNotBlank { put("holderName", JsonPrimitive(it)) }
            block.qrLabel.ifNotBlank { put("qrLabel", JsonPrimitive(it)) }
            actionToJson(block.action)?.let { put("action", it) }
        }
    }

private fun actionToJson(action: NativeUiActionDraft): JsonObject? =
    when (action.type) {
        NativeUiActionType.None -> null
        NativeUiActionType.Page -> buildJsonObject {
            put("type", JsonPrimitive("page"))
            action.pageId.ifNotBlank { put("pageId", JsonPrimitive(it)) }
            action.slug.ifNotBlank { put("slug", JsonPrimitive(it)) }
        }

        NativeUiActionType.Url -> buildJsonObject {
            put("type", JsonPrimitive("url"))
            put("url", JsonPrimitive(action.url))
        }

        NativeUiActionType.Refresh -> buildJsonObject {
            put("type", JsonPrimitive("refresh"))
        }

        NativeUiActionType.Custom -> buildJsonObject {
            put("type", JsonPrimitive("custom"))
            put("actionId", JsonPrimitive(action.actionId))
            action.payload.ifNotBlank { put("payload", JsonPrimitive(it)) }
        }
    }

private fun parseDocumentDraft(rawJson: String): NativeUiDocumentDraft {
    val root = guidedEditorJson.parseToJsonElement(rawJson).jsonObject
    ensureOnlyKeys(root, setOf("id", "version", "rootPageId", "pages"), "Document")
    val pages = root.requiredArray("pages", "Document").mapIndexed { index, element ->
        parsePageDraft(element.jsonObject, "Document page[$index]")
    }
    return NativeUiDocumentDraft(
        id = root.requiredString("id", "Document"),
        version = root.requiredString("version", "Document"),
        rootPageId = root.requiredString("rootPageId", "Document"),
        pages = pages,
    )
}

private fun parsePageDraft(page: JsonObject, path: String): NativeUiPageDraft {
    ensureOnlyKeys(page, setOf("id", "slug", "title", "blocks"), path)
    return NativeUiPageDraft(
        id = page.requiredString("id", path),
        slug = page.optionalString("slug"),
        title = page.optionalString("title"),
        blocks = page.requiredArray("blocks", path).mapIndexed { index, element ->
            parseBlockDraft(element.jsonObject, "$path block[$index]")
        },
    )
}

private fun parseBlockDraft(block: JsonObject, path: String): NativeUiBlockDraft {
    val type = block.requiredString("type", path)
    return when (NativeUiBlockType.entries.firstOrNull { it.wireValue == type }) {
        NativeUiBlockType.Text -> {
            ensureOnlyKeys(block, setOf("type", "id", "text", "variant", "colorRole"), path)
            NativeUiTextBlockDraft(
                id = block.optionalString("id"),
                text = block.requiredString("text", path),
                variant = parseEnum(
                    value = block.optionalString("variant").ifBlank { NativeUiTextVariant.Body.wireValue },
                    options = NativeUiTextVariant.entries,
                    path = "$path variant",
                ),
                colorRole = block.optionalEnum("colorRole", NativeUiColorRoleDraft.entries, "$path colorRole"),
            )
        }

        NativeUiBlockType.Image -> {
            ensureOnlyKeys(block, setOf("type", "id", "url", "contentDescription", "aspectRatio"), path)
            NativeUiImageBlockDraft(
                id = block.optionalString("id"),
                url = block.requiredString("url", path),
                contentDescription = block.optionalString("contentDescription"),
                aspectRatio = block["aspectRatio"]?.jsonPrimitive?.contentOrNull.orEmpty(),
            )
        }

        NativeUiBlockType.Button -> {
            ensureOnlyKeys(
                block,
                setOf("type", "id", "label", "action", "style", "containerColorRole", "contentColorRole", "borderColorRole"),
                path,
            )
            NativeUiButtonBlockDraft(
                id = block.optionalString("id"),
                label = block.requiredString("label", path),
                action = block.optionalAction("$path action"),
                style = parseEnum(
                    value = block.optionalString("style").ifBlank { NativeUiButtonStyleDraft.Primary.wireValue },
                    options = NativeUiButtonStyleDraft.entries,
                    path = "$path style",
                ),
                containerColorRole = block.optionalEnum("containerColorRole", NativeUiColorRoleDraft.entries, "$path containerColorRole"),
                contentColorRole = block.optionalEnum("contentColorRole", NativeUiColorRoleDraft.entries, "$path contentColorRole"),
                borderColorRole = block.optionalEnum("borderColorRole", NativeUiColorRoleDraft.entries, "$path borderColorRole"),
            )
        }

        NativeUiBlockType.Spacer -> {
            ensureOnlyKeys(block, setOf("type", "id", "heightDp"), path)
            NativeUiSpacerBlockDraft(
                id = block.optionalString("id"),
                heightDp = block["heightDp"]?.jsonPrimitive?.intOrNull
                    ?: error("$path heightDp must be an integer"),
            )
        }

        NativeUiBlockType.Section -> {
            ensureOnlyKeys(block, setOf("type", "id", "title", "blocks"), path)
            NativeUiSectionBlockDraft(
                id = block.optionalString("id"),
                title = block.optionalString("title"),
                blocks = block.requiredArray("blocks", path).mapIndexed { index, element ->
                    parseBlockDraft(element.jsonObject, "$path nested block[$index]")
                },
            )
        }

        NativeUiBlockType.Card -> {
            ensureOnlyKeys(
                block,
                setOf("type", "id", "title", "body", "action", "blocks", "style", "containerColorRole", "contentColorRole", "borderColorRole"),
                path,
            )
            NativeUiCardBlockDraft(
                id = block.optionalString("id"),
                title = block.optionalString("title"),
                body = block.optionalString("body"),
                action = block.optionalAction("$path action"),
                blocks = block["blocks"]?.jsonArray?.mapIndexed { index, element ->
                    parseBlockDraft(element.jsonObject, "$path nested block[$index]")
                }.orEmpty(),
                style = parseEnum(
                    value = block.optionalString("style").ifBlank { NativeUiCardStyleDraft.Standard.wireValue },
                    options = NativeUiCardStyleDraft.entries,
                    path = "$path style",
                ),
                containerColorRole = block.optionalEnum("containerColorRole", NativeUiColorRoleDraft.entries, "$path containerColorRole"),
                contentColorRole = block.optionalEnum("contentColorRole", NativeUiColorRoleDraft.entries, "$path contentColorRole"),
                borderColorRole = block.optionalEnum("borderColorRole", NativeUiColorRoleDraft.entries, "$path borderColorRole"),
            )
        }

        NativeUiBlockType.List -> {
            ensureOnlyKeys(block, setOf("type", "id", "items"), path)
            NativeUiListBlockDraft(
                id = block.optionalString("id"),
                items = block.requiredArray("items", path).mapIndexed { index, element ->
                    parseListItem(element.jsonObject, "$path item[$index]")
                },
            )
        }

        NativeUiBlockType.EventCard -> {
            ensureOnlyKeys(block, setOf("type", "id", "title", "subtitle", "dateLabel", "locationLabel", "imageUrl", "action"), path)
            NativeUiEventCardBlockDraft(
                id = block.optionalString("id"),
                title = block.requiredString("title", path),
                subtitle = block.optionalString("subtitle"),
                dateLabel = block.optionalString("dateLabel"),
                locationLabel = block.optionalString("locationLabel"),
                imageUrl = block.optionalString("imageUrl"),
                action = block.optionalAction("$path action"),
            )
        }

        NativeUiBlockType.TicketCard -> {
            ensureOnlyKeys(block, setOf("type", "id", "title", "subtitle", "status", "holderName", "qrLabel", "action"), path)
            NativeUiTicketCardBlockDraft(
                id = block.optionalString("id"),
                title = block.requiredString("title", path),
                subtitle = block.optionalString("subtitle"),
                status = block.optionalString("status"),
                holderName = block.optionalString("holderName"),
                qrLabel = block.optionalString("qrLabel"),
                action = block.optionalAction("$path action"),
            )
        }

        null -> error("$path uses unsupported block type \"$type\". Use the advanced JSON editor for this document.")
    }
}

private fun parseListItem(item: JsonObject, path: String): NativeUiListItemDraft {
    ensureOnlyKeys(item, setOf("title", "subtitle", "overline", "action"), path)
    return NativeUiListItemDraft(
        title = item.requiredString("title", path),
        subtitle = item.optionalString("subtitle"),
        overline = item.optionalString("overline"),
        action = item.optionalAction("$path action"),
    )
}

private fun JsonObject.optionalAction(path: String): NativeUiActionDraft {
    val action = this["action"] ?: return NativeUiActionDraft()
    val objectValue = action.jsonObject
    val type = objectValue.requiredString("type", path)
    return when (type) {
        "page" -> {
            ensureOnlyKeys(objectValue, setOf("type", "pageId", "slug"), path)
            NativeUiActionDraft(
                type = NativeUiActionType.Page,
                pageId = objectValue.optionalString("pageId"),
                slug = objectValue.optionalString("slug"),
            )
        }

        "url" -> {
            ensureOnlyKeys(objectValue, setOf("type", "url"), path)
            NativeUiActionDraft(
                type = NativeUiActionType.Url,
                url = objectValue.requiredString("url", path),
            )
        }

        "refresh" -> {
            ensureOnlyKeys(objectValue, setOf("type"), path)
            NativeUiActionDraft(type = NativeUiActionType.Refresh)
        }

        "custom" -> {
            ensureOnlyKeys(objectValue, setOf("type", "actionId", "payload"), path)
            NativeUiActionDraft(
                type = NativeUiActionType.Custom,
                actionId = objectValue.requiredString("actionId", path),
                payload = objectValue.optionalString("payload"),
            )
        }

        else -> error("$path uses unsupported action type \"$type\". Use the advanced JSON editor for this document.")
    }
}

private fun createSuggestedDocumentDraft(
    requiredTabRouteIds: List<String>,
    homeTabId: String,
): NativeUiDocumentDraft {
    val pageIds = requiredTabRouteIds.ifEmpty {
        listOf(homeTabId.ifBlank { "home" })
    }
    val rootPageId = when {
        homeTabId.isNotBlank() && homeTabId in pageIds -> homeTabId
        pageIds.isNotEmpty() -> pageIds.first()
        else -> "home"
    }
    return NativeUiDocumentDraft(
        id = "selu-app",
        version = "1.0",
        rootPageId = rootPageId,
        pages = pageIds.map { pageId ->
            NativeUiPageDraft(
                id = pageId,
                title = humanizeRouteId(pageId),
                blocks = listOf(
                    NativeUiTextBlockDraft(
                        text = humanizeRouteId(pageId),
                        variant = NativeUiTextVariant.Title,
                    ),
                    NativeUiTextBlockDraft(
                        text = "Draft content for ${humanizeRouteId(pageId)}.",
                        variant = NativeUiTextVariant.Body,
                    ),
                ),
            )
        },
    )
}

@Composable
internal fun NativeUiDocumentGuidedEditor(
    draft: NativeUiDocumentDraft,
    selectedPageId: String?,
    onSelectedPageChange: (String?) -> Unit,
    requiredTabRouteIds: List<String>,
    homeTabId: String,
    canEdit: Boolean,
    theme: MaterialThemePalette,
    onChange: (NativeUiDocumentDraft) -> Unit,
) {
    val selectedPage = draft.pages.firstOrNull { it.id == selectedPageId }
        ?: draft.pages.firstOrNull { it.id == draft.rootPageId }
        ?: draft.pages.firstOrNull()
    val missingRequiredTabRouteIds = requiredTabRouteIds.filterNot { requiredId ->
        draft.pages.any { page -> page.id == requiredId }
    }

    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(FlexDirection.Column)
                gap(16.px)
            }
        }
    ) {
        EditorPanel(
            title = "App Document Builder",
            description = "Build the NativeUI app document with pages, blocks, and actions. This still saves the same app-document JSON contract.",
            theme = theme,
        ) {
            FieldRow {
                TextField(
                    theme = theme,
                    label = "Document ID",
                    value = draft.id,
                    placeholder = "selu-app",
                    onValueChange = { if (canEdit) onChange(draft.copy(id = it)) },
                )
                TextField(
                    theme = theme,
                    label = "Version",
                    value = draft.version,
                    placeholder = "1.0",
                    onValueChange = { if (canEdit) onChange(draft.copy(version = it)) },
                )
            }

            StringSelectField(
                theme = theme,
                label = "Root Page",
                value = draft.rootPageId,
                options = draft.pages.map { it.id to (it.title.ifBlank { humanizeRouteId(it.id) } + " (${it.id})") },
                emptyLabel = if (draft.pages.isEmpty()) "Add a page first" else "Select a root page",
                isDisabled = !canEdit || draft.pages.isEmpty(),
                onValueChange = { nextRoot ->
                    if (canEdit && nextRoot.isNotBlank()) {
                        onChange(draft.copy(rootPageId = nextRoot))
                    }
                },
            )

            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("font-size", "0.86rem")
                        property("color", theme.onSurfaceVariant)
                        property("line-height", "1.5")
                    }
                }
            ) {
                Text(
                    if (requiredTabRouteIds.isEmpty()) {
                        "No required tab route IDs are configured yet."
                    } else {
                        "Expected consumer tab root pages: ${requiredTabRouteIds.joinToString(", ")}. Home tab route ID is \"$homeTabId\"."
                    }
                )
            }
        }

        EditorPanel(
            title = "Pages",
            description = "Add tab root pages or subpages, then choose one page to edit its blocks.",
            theme = theme,
        ) {
            if (missingRequiredTabRouteIds.isNotEmpty()) {
                Div(
                    attrs = {
                        style {
                            display(DisplayStyle.Flex)
                            flexDirection(FlexDirection.Column)
                            gap(10.px)
                        }
                    }
                ) {
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "0.8rem")
                                property("font-weight", "700")
                                property("letter-spacing", "0.06em")
                                property("text-transform", "uppercase")
                                property("color", theme.onSurfaceVariant)
                            }
                        }
                    ) {
                        Text("Missing Tab Pages")
                    }
                    Div(
                        attrs = {
                            style {
                                display(DisplayStyle.Flex)
                                gap(10.px)
                                property("flex-wrap", "wrap")
                            }
                        }
                    ) {
                        missingRequiredTabRouteIds.forEach { missingRouteId ->
                            ActionButton(
                                label = "Add ${humanizeRouteId(missingRouteId)} Tab",
                                onClick = {
                                    if (!canEdit) return@ActionButton
                                    val nextPage = NativeUiPageDraft(
                                        id = missingRouteId,
                                        title = humanizeRouteId(missingRouteId),
                                        blocks = listOf(
                                            NativeUiTextBlockDraft(
                                                text = humanizeRouteId(missingRouteId),
                                                variant = NativeUiTextVariant.Title,
                                            ),
                                            NativeUiTextBlockDraft(
                                                text = "Draft content for ${humanizeRouteId(missingRouteId)}.",
                                                variant = NativeUiTextVariant.Body,
                                            ),
                                        ),
                                    )
                                    onChange(draft.copy(pages = draft.pages + nextPage))
                                    onSelectedPageChange(nextPage.id)
                                },
                                theme = theme,
                                isDisabled = !canEdit,
                                isPrimary = false,
                            )
                        }
                    }
                }
            }

            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        gap(12.px)
                        property("flex-wrap", "wrap")
                    }
                }
            ) {
                draft.pages.forEach { page ->
                    PageChip(
                        page = page,
                        isSelected = selectedPage?.id == page.id,
                        isRoot = page.id == draft.rootPageId,
                        requiredTabRouteIds = requiredTabRouteIds,
                        theme = theme,
                        onClick = { onSelectedPageChange(page.id) },
                    )
                }
            }

            ActionButton(
                label = "Add Subpage",
                onClick = {
                    if (!canEdit) return@ActionButton
                    val nextId = nextAvailablePageId(draft.pages)
                    val nextPage = NativeUiPageDraft(
                        id = nextId,
                        title = humanizeRouteId(nextId),
                        blocks = listOf(
                            NativeUiTextBlockDraft(
                                text = humanizeRouteId(nextId),
                                variant = NativeUiTextVariant.Title,
                            ),
                        ),
                    )
                    val nextPages = draft.pages + nextPage
                    val nextRoot = draft.rootPageId.ifBlank { nextPage.id }
                    onChange(draft.copy(pages = nextPages, rootPageId = nextRoot))
                    onSelectedPageChange(nextPage.id)
                },
                theme = theme,
                isDisabled = !canEdit,
                isPrimary = false,
            )
        }

        if (selectedPage != null) {
            EditorPanel(
                title = "Page Details",
                description = "Edit the selected page metadata and the blocks rendered on that page.",
                theme = theme,
            ) {
                FieldRow {
                    TextField(
                        theme = theme,
                        label = "Page ID",
                        value = selectedPage.id,
                        placeholder = "home",
                        onValueChange = { nextId ->
                            if (!canEdit) return@TextField
                            val updatedPages = draft.pages.map { page ->
                                if (page.id == selectedPage.id) page.copy(id = nextId) else page
                            }
                            val updatedRoot = if (draft.rootPageId == selectedPage.id) nextId else draft.rootPageId
                            onChange(draft.copy(pages = updatedPages, rootPageId = updatedRoot))
                            onSelectedPageChange(nextId)
                        },
                    )
                    TextField(
                        theme = theme,
                        label = "Title",
                        value = selectedPage.title,
                        placeholder = humanizeRouteId(selectedPage.id),
                        onValueChange = { nextTitle ->
                            if (canEdit) {
                                onChange(
                                    draft.copy(
                                        pages = draft.pages.map { page ->
                                            if (page.id == selectedPage.id) page.copy(title = nextTitle) else page
                                        },
                                    )
                                )
                            }
                        },
                    )
                }

                TextField(
                    theme = theme,
                    label = "Slug",
                    value = selectedPage.slug,
                    placeholder = "optional-page-slug",
                    onValueChange = { nextSlug ->
                        if (canEdit) {
                            onChange(
                                draft.copy(
                                    pages = draft.pages.map { page ->
                                        if (page.id == selectedPage.id) page.copy(slug = nextSlug) else page
                                    },
                                )
                            )
                        }
                    },
                )

                FieldRow {
                    ActionButton(
                        label = if (selectedPage.id == draft.rootPageId) "Root Page" else "Set As Root",
                        onClick = { if (canEdit) onChange(draft.copy(rootPageId = selectedPage.id)) },
                        theme = theme,
                        isDisabled = !canEdit || selectedPage.id == draft.rootPageId,
                        isPrimary = false,
                    )
                    ActionButton(
                        label = "Remove Page",
                        onClick = {
                            if (!canEdit) return@ActionButton
                            val remainingPages = draft.pages.filterNot { it.id == selectedPage.id }
                            val nextRoot = when {
                                remainingPages.isEmpty() -> ""
                                draft.rootPageId == selectedPage.id -> remainingPages.first().id
                                else -> draft.rootPageId
                            }
                            onChange(draft.copy(pages = remainingPages, rootPageId = nextRoot))
                            onSelectedPageChange(remainingPages.firstOrNull()?.id)
                        },
                        theme = theme,
                        isDisabled = !canEdit,
                        isPrimary = false,
                    )
                }

                NativeUiBlockListEditor(
                    label = "Page Blocks",
                    pathKey = "page-${selectedPage.id}",
                    blocks = selectedPage.blocks,
                    availablePages = draft.pages,
                    canEdit = canEdit,
                    theme = theme,
                    onChange = { nextBlocks ->
                        onChange(
                            draft.copy(
                                pages = draft.pages.map { page ->
                                    if (page.id == selectedPage.id) page.copy(blocks = nextBlocks) else page
                                },
                            )
                        )
                    },
                )
            }
        }
    }
}

@Composable
private fun NativeUiBlockListEditor(
    label: String,
    pathKey: String,
    blocks: List<NativeUiBlockDraft>,
    availablePages: List<NativeUiPageDraft>,
    canEdit: Boolean,
    theme: MaterialThemePalette,
    onChange: (List<NativeUiBlockDraft>) -> Unit,
) {
    var nextBlockType by remember(pathKey) { mutableStateOf(NativeUiBlockType.Text) }

    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(FlexDirection.Column)
                gap(14.px)
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.82rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.06em")
                    property("text-transform", "uppercase")
                    property("color", theme.onSurfaceVariant)
                }
            }
        ) {
            Text(label)
        }

        if (blocks.isEmpty()) {
            P(
                attrs = {
                    style {
                        margin(0.px)
                        padding(14.px)
                        borderRadius(16.px)
                        property("background", theme.surfaceContainerHighest)
                        property("border", "1px dashed ${theme.outlineVariant}")
                        property("color", theme.onSurfaceVariant)
                        property("line-height", "1.5")
                    }
                }
            ) {
                Text("No blocks yet. Add a supported block type below.")
            }
        }

        blocks.forEachIndexed { index, block ->
            BlockEditorCard(
                block = block,
                pathKey = "$pathKey-$index-${block.type.wireValue}",
                availablePages = availablePages,
                canEdit = canEdit,
                theme = theme,
                onChange = { nextBlock ->
                    onChange(blocks.replaceAt(index, nextBlock))
                },
                onRemove = { onChange(blocks.removeAt(index)) },
            )
        }

        FieldRow {
            StringSelectField(
                theme = theme,
                label = "Add Block Type",
                value = nextBlockType.wireValue,
                options = NativeUiBlockType.entries.map { it.wireValue to it.label },
                emptyLabel = "Choose block type",
                isDisabled = !canEdit,
                onValueChange = { selected ->
                    NativeUiBlockType.entries.firstOrNull { it.wireValue == selected }?.let { nextBlockType = it }
                },
            )
            ActionButton(
                label = "Add Block",
                onClick = { if (canEdit) onChange(blocks + defaultBlockDraft(nextBlockType)) },
                theme = theme,
                isDisabled = !canEdit,
                isPrimary = false,
            )
        }
    }
}

@Composable
private fun BlockEditorCard(
