@Composable
private fun ActionEditor(
    action: NativeUiActionDraft,
    availablePages: List<NativeUiPageDraft>,
    canEdit: Boolean,
    theme: MaterialThemePalette,
    onChange: (NativeUiActionDraft) -> Unit,
) {
    EditorPanel(
        title = "Action",
        description = "Choose what happens when this block is tapped.",
        theme = theme,
    ) {
        StringSelectField(
            theme = theme,
            label = "Action Type",
            value = action.type.name,
            options = NativeUiActionType.entries.map { it.name to it.label },
            isDisabled = !canEdit,
            onValueChange = { nextType ->
                if (canEdit) {
                    onChange(NativeUiActionDraft(type = NativeUiActionType.valueOf(nextType)))
                }
            },
        )

        when (action.type) {
            NativeUiActionType.None,
            NativeUiActionType.Refresh,
            -> Unit

            NativeUiActionType.Page -> {
                FieldRow {
                    StringSelectField(
                        theme = theme,
                        label = "Target Page",
                        value = action.pageId,
                        options = availablePages.map { page ->
                            page.id to (page.title.ifBlank { humanizeRouteId(page.id) } + " (${page.id})")
                        },
                        emptyLabel = "Select a page or use slug",
                        isDisabled = !canEdit,
                        onValueChange = { nextPageId ->
                            if (canEdit) onChange(action.copy(pageId = nextPageId))
                        },
                    )
                    TextField(
                        theme = theme,
                        label = "Target Slug",
                        value = action.slug,
                        placeholder = "optional-page-slug",
                        onValueChange = { nextSlug -> if (canEdit) onChange(action.copy(slug = nextSlug)) },
                    )
                }
            }

            NativeUiActionType.Url -> {
                TextField(
                    theme = theme,
                    label = "URL",
                    value = action.url,
                    placeholder = "https://example.com",
                    onValueChange = { nextUrl -> if (canEdit) onChange(action.copy(url = nextUrl)) },
                )
            }

            NativeUiActionType.Custom -> {
                FieldRow {
                    TextField(
                        theme = theme,
                        label = "Action ID",
                        value = action.actionId,
                        placeholder = "custom-action-id",
                        onValueChange = { nextActionId -> if (canEdit) onChange(action.copy(actionId = nextActionId)) },
                    )
                    TextField(
                        theme = theme,
                        label = "Payload",
                        value = action.payload,
                        placeholder = "optional-payload",
                        onValueChange = { nextPayload -> if (canEdit) onChange(action.copy(payload = nextPayload)) },
                    )
                }
            }
        }
    }
}

