@Composable
private fun StringSelectField(
    theme: MaterialThemePalette,
    label: String,
    value: String,
    options: List<Pair<String, String>>,
    emptyLabel: String = "Select",
    isDisabled: Boolean = false,
    onValueChange: (String) -> Unit,
) {
    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(FlexDirection.Column)
                gap(6.px)
                flex(1)
                property("min-width", "180px")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("color", theme.onSurfaceVariant)
                    property("font-size", "0.78rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.06em")
                    property("text-transform", "uppercase")
                }
            }
        ) {
            Text(label)
        }
        Select(
            attrs = {
                onChange { onValueChange(it.value ?: "") }
                if (isDisabled) disabled()
                style {
                    padding(14.px, 16.px)
                    borderRadius(14.px)
                    property("box-sizing", "border-box")
                    property("width", "100%")
                    property("background-color", theme.surface)
                    property("color", theme.onSurface)
                    property("border", "1px solid ${theme.outline}")
                    property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
                    property("font-size", "0.94rem")
                }
            }
        ) {
            Option(
                value = "",
                attrs = {
                    if (value.isBlank()) selected()
                }
            ) {
                Text(emptyLabel)
            }
            options.forEach { (optionValue, optionLabel) ->
                Option(
                    value = optionValue,
                    attrs = {
                        if (value == optionValue) selected()
                    }
                ) {
                    Text(optionLabel)
                }
            }
        }
    }
}

private fun updateBlockId(block: NativeUiBlockDraft, nextId: String): NativeUiBlockDraft =
    when (block) {
        is NativeUiTextBlockDraft -> block.copy(id = nextId)
        is NativeUiImageBlockDraft -> block.copy(id = nextId)
        is NativeUiButtonBlockDraft -> block.copy(id = nextId)
        is NativeUiSpacerBlockDraft -> block.copy(id = nextId)
        is NativeUiSectionBlockDraft -> block.copy(id = nextId)
        is NativeUiCardBlockDraft -> block.copy(id = nextId)
        is NativeUiListBlockDraft -> block.copy(id = nextId)
        is NativeUiEventCardBlockDraft -> block.copy(id = nextId)
        is NativeUiTicketCardBlockDraft -> block.copy(id = nextId)
    }

private fun defaultBlockDraft(type: NativeUiBlockType): NativeUiBlockDraft =
    when (type) {
        NativeUiBlockType.Text -> NativeUiTextBlockDraft(text = "New text block")
        NativeUiBlockType.Image -> NativeUiImageBlockDraft(url = "https://example.com/image.png")
        NativeUiBlockType.Button -> NativeUiButtonBlockDraft(label = "New Button")
        NativeUiBlockType.Spacer -> NativeUiSpacerBlockDraft()
        NativeUiBlockType.Section -> NativeUiSectionBlockDraft(title = "Section Title")
        NativeUiBlockType.Card -> NativeUiCardBlockDraft(title = "Card Title")
        NativeUiBlockType.List -> NativeUiListBlockDraft(items = listOf(NativeUiListItemDraft(title = "New item")))
        NativeUiBlockType.EventCard -> NativeUiEventCardBlockDraft(title = "Event Title")
        NativeUiBlockType.TicketCard -> NativeUiTicketCardBlockDraft(title = "Ticket Title")
    }

private fun nextAvailablePageId(pages: List<NativeUiPageDraft>): String {
    val existingIds = pages.map { it.id }.toSet()
    var index = pages.size + 1
    var candidate = "page-$index"
    while (candidate in existingIds) {
        index += 1
        candidate = "page-$index"
    }
    return candidate
}

private fun humanizeRouteId(routeId: String): String =
    routeId
        .split('-', '_')
        .filter { it.isNotBlank() }
        .joinToString(" ") { token ->
            token.replaceFirstChar { if (it.isLowerCase()) it.titlecase() else it.toString() }
        }
        .ifBlank { "Untitled Page" }

private fun ensureOnlyKeys(value: JsonObject, allowedKeys: Set<String>, path: String) {
    val unsupportedKeys = value.keys - allowedKeys
    if (unsupportedKeys.isNotEmpty()) {
        error("$path uses unsupported field(s): ${unsupportedKeys.joinToString(", ")}. Use the advanced JSON editor for this document.")
    }
}

private fun JsonObject.requiredString(key: String, path: String): String =
    this[key]?.jsonPrimitive?.contentOrNull
        ?: error("$path is missing required \"$key\".")

private fun JsonObject.optionalString(key: String): String =
    this[key]?.jsonPrimitive?.contentOrNull.orEmpty()

private fun JsonObject.requiredArray(key: String, path: String): List<JsonElement> =
    this[key]?.jsonArray ?: error("$path is missing required \"$key\".")

private fun <T> parseEnum(
    value: String,
    options: List<T>,
    path: String,
): T where T : Enum<T> {
    return options.firstOrNull { option -> option.name.equals(value, ignoreCase = true) }
        ?: error("$path uses unsupported value \"$value\".")
}

private fun <T> JsonObject.optionalEnum(
    key: String,
    options: List<T>,
    path: String,
): T? where T : Enum<T> {
    val value = this[key]?.jsonPrimitive?.contentOrNull ?: return null
    return parseEnum(value = value, options = options, path = path)
}

private fun String.ifNotBlank(block: (String) -> Unit) {
    if (isNotBlank()) block(this)
}

private fun <T> List<T>.replaceAt(index: Int, value: T): List<T> =
    mapIndexed { currentIndex, currentValue ->
        if (currentIndex == index) value else currentValue
    }

private fun <T> List<T>.removeAt(index: Int): List<T> =
    filterIndexed { currentIndex, _ -> currentIndex != index }
