private val runtimeJson = Json {
    prettyPrint = true
    explicitNulls = false
}

private val defaultConsumerTabRouteIds = listOf("home", "events", "wallet", "account")
private const val defaultConsumerHomeTabId = "home"

private data class ThemeFieldSpec(
    val key: String,
    val label: String,
    val placeholder: String,
)

private data class ConsumerRuntimePreviewModel(
    val defaultScreenId: String?,
    val fallbackEyebrow: String,
    val fallbackTitle: String,
    val fallbackBody: String,
    val fallbackButtons: List<String>,
    val screens: List<ConsumerRuntimeScreenPreview>,
)

private data class ConsumerRuntimeScreenPreview(
    val id: String,
    val label: String,
    val blockCount: Int,
    val isRoot: Boolean,
    val previewEyebrow: String,
    val previewTitle: String,
    val previewBody: String,
    val previewButtons: List<String>,
)

private enum class AppDocumentValidationTone {
    Success,
    Info,
    Error,
}

private data class AppDocumentValidation(
    val tone: AppDocumentValidationTone,
    val message: String,
)

private val commonThemeFields = listOf(
    ThemeFieldSpec("primary", "Primary", "#0B5FFF"),
    ThemeFieldSpec("onPrimary", "On Primary", "#FFFFFF"),
    ThemeFieldSpec("secondary", "Secondary", "#3BB273"),
    ThemeFieldSpec("onSecondary", "On Secondary", "#0C1B14"),
    ThemeFieldSpec("background", "Background", "#F5F7FB"),
    ThemeFieldSpec("onBackground", "On Background", "#102033"),
    ThemeFieldSpec("surface", "Surface", "#FFFFFF"),
    ThemeFieldSpec("onSurface", "On Surface", "#122033"),
    ThemeFieldSpec("surfaceVariant", "Surface Variant", "#DCE7F5"),
    ThemeFieldSpec("onSurfaceVariant", "On Surface Variant", "#50627A"),
    ThemeFieldSpec("outline", "Outline", "#9EB0C6"),
    ThemeFieldSpec("logoUrl", "Logo URL", "https://example.com/logo.png"),
)

@Composable
fun SettingsScreen(
    apiClient: AdminApiClient,
    district: SelectedDistrictContext?,
    districtLoading: Boolean,
    districtLoadError: String?,
    theme: MaterialThemePalette,
    onDistrictTaxRateUpdated: (Int) -> Unit,
    canEdit: Boolean,
) {
    val scope = rememberCoroutineScope()
    val selectedDistrict = district
    var settings by remember { mutableStateOf<DistrictSettingsResponse?>(null) }
    var draftTaxRate by remember { mutableStateOf("") }
    var draftConsumerThemeJson by remember { mutableStateOf("") }
    var draftAppDocumentJson by remember { mutableStateOf("") }
    var draftRequiredTabRouteIds by remember { mutableStateOf(defaultConsumerTabRouteIds.joinToString(", ")) }
    var draftHomeTabId by remember { mutableStateOf(defaultConsumerHomeTabId) }
    var showAdvancedAppDocumentJson by remember { mutableStateOf(false) }
    var isLoading by remember { mutableStateOf(false) }
    var isSaving by remember { mutableStateOf(false) }
    var loadError by remember { mutableStateOf<String?>(null) }
    var taxSaveError by remember { mutableStateOf<String?>(null) }
    var taxSaveMessage by remember { mutableStateOf<String?>(null) }
    var runtimeSaveError by remember { mutableStateOf<String?>(null) }
    var runtimeSaveMessage by remember { mutableStateOf<String?>(null) }
    val parsedThemeObject = remember(draftConsumerThemeJson) { parseJsonObjectOrNull(draftConsumerThemeJson) }
    val themeJsonError = remember(draftConsumerThemeJson) { jsonObjectError(draftConsumerThemeJson) }
    val appDocumentError = remember(draftAppDocumentJson) { jsonObjectError(draftAppDocumentJson) }
    val requiredTabRouteIds = remember(draftRequiredTabRouteIds) { parseRouteIds(draftRequiredTabRouteIds) }
    val normalizedHomeTabId = remember(draftHomeTabId) { draftHomeTabId.trim() }
    val previewModel = remember(draftAppDocumentJson) { buildConsumerRuntimePreviewModel(draftAppDocumentJson) }
    val appDocumentEditorAvailability = remember(
        draftAppDocumentJson,
        requiredTabRouteIds,
        normalizedHomeTabId,
    ) {
        resolveAppDocumentEditorAvailability(
            rawJson = draftAppDocumentJson,
            requiredTabRouteIds = requiredTabRouteIds,
            homeTabId = normalizedHomeTabId,
        )
    }
    var selectedPreviewScreenId by remember { mutableStateOf<String?>(null) }
    val appDocumentValidation = remember(
        draftAppDocumentJson,
        appDocumentError,
        requiredTabRouteIds,
        normalizedHomeTabId,
    ) {
        validateAppDocument(
            rawDocumentJson = draftAppDocumentJson,
            documentJsonError = appDocumentError,
            requiredTabRouteIds = requiredTabRouteIds,
            homeTabId = normalizedHomeTabId,
        )
    }

    LaunchedEffect(previewModel.screens) {
        selectedPreviewScreenId = when {
            previewModel.screens.isEmpty() -> null
            selectedPreviewScreenId != null && previewModel.screens.any { it.id == selectedPreviewScreenId } -> selectedPreviewScreenId
            else -> previewModel.defaultScreenId ?: previewModel.screens.first().id
        }
    }

    fun settingsUnavailableMessage(): String =
        when {
            districtLoading -> "Loading district context..."
            districtLoadError != null -> "District context could not be loaded. Refresh context and select a district to manage settings."
            else -> "Select a district to manage district settings."
        }

    suspend fun loadSettings(currentDistrict: SelectedDistrictContext) {
        isLoading = true
        loadError = null
        try {
            val response = apiClient.getDistrictSettings(currentDistrict.id)
            settings = response
            draftTaxRate = formatTaxRateInput(response.defaultTaxRateBps)
            draftConsumerThemeJson = response.consumerApp?.nativeUiThemeJson.orEmpty()
            draftAppDocumentJson = response.consumerApp?.appDocumentJson.orEmpty()
        } catch (exception: Exception) {
            loadError = exception.message ?: "Unable to load district settings."
        } finally {
            isLoading = false
        }
    }

    LaunchedEffect(selectedDistrict?.id, districtLoading, districtLoadError) {
        taxSaveError = null
        taxSaveMessage = null
        runtimeSaveError = null
        runtimeSaveMessage = null

        if (selectedDistrict == null) {
            settings = null
            draftTaxRate = ""
            draftConsumerThemeJson = ""
            draftAppDocumentJson = ""
            showAdvancedAppDocumentJson = false
            loadError = settingsUnavailableMessage()
            return@LaunchedEffect
        }

        loadSettings(selectedDistrict)
    }

    SectionCard(
        title = "District Settings",
        theme = theme,
        description = "Review district-wide defaults for the currently selected district.",
    ) {
        if (selectedDistrict == null) {
            StatusBanner(
                message = settingsUnavailableMessage(),
                theme = theme,
                tone = if (districtLoadError != null) BannerTone.Error else BannerTone.Info,
            )
        } else {
            if (!canEdit) {
                StatusBanner(
                    message = "Read-only access. District setting changes require district edit permission.",
                    theme = theme,
                )
            }
            SettingsSummaryPanel(
                district = selectedDistrict,
                effectiveTaxRateBps = settings?.defaultTaxRateBps ?: selectedDistrict.defaultTaxRateBps ?: 0,
                hasConsumerRuntimeSettings = settings?.consumerApp != null,
                theme = theme,
            )
        }
    }

    if (selectedDistrict != null) {
        SectionCard(
            title = "Sales Tax",
            theme = theme,
            description = "Taxable products use this district default sales tax rate. Tax-exempt products always use zero tax.",
            headerActions = {
                ActionButton(
                    label = if (isLoading) "Loading..." else "Reload",
                    onClick = {
                        scope.launch {
                            loadSettings(selectedDistrict)
                        }
                    },
                    theme = theme,
                    isPrimary = false,
                    isDisabled = isLoading || isSaving || !canEdit,
                )
            },
        ) {
            loadError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            taxSaveError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            taxSaveMessage?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Success,
                )
            }

            settings?.taxRules?.takeIf { it.isNotEmpty() }?.let { taxRules ->
                Div(
                    attrs = {
                        style {
                            display(DisplayStyle.Flex)
                            flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                            gap(10.px)
                            padding(16.px)
                            borderRadius(22.px)
                            property(
                                "background",
                                "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surfaceVariant} 100%)"
                            )
                            property("border", "1px solid ${theme.outlineVariant}")
                            property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
                        }
                    }
                ) {
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "0.8rem")
                                property("font-weight", "700")
                                property("letter-spacing", "0.08em")
                                property("text-transform", "uppercase")
                                property("color", theme.onSurfaceVariant)
                            }
                        }
                    ) {
                        Text("Returned Tax Rules")
                    }

                    taxRules.forEach { taxRule ->
                        P(
                            attrs = {
                                style {
                                    margin(0.px)
                                    property("color", theme.onSurfaceVariant)
                                    property("font-size", "0.92rem")
                                    property("line-height", "1.5")
                                }
                            }
                        ) {
                            Text("${taxRule.name}: ${formatTaxRatePercent(taxRule.rateBps)}")
                        }
                    }
                }
            }

            TextField(
                theme = theme,
                label = "Default Sales Tax Rate",
                value = draftTaxRate,
                placeholder = "7.25",
                onValueChange = {
                    if (canEdit) {
                        draftTaxRate = it
                        taxSaveError = null
                        taxSaveMessage = null
                    }
                },
            )

            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("color", theme.onSurfaceVariant)
                        property("font-size", "0.9rem")
                        property("line-height", "1.5")
                    }
                }
            ) {
                Text("Enter a percentage such as 7.25. Kanati stores this as basis points and applies it only to products marked Taxable.")
            }

            ActionButton(
                label = if (isSaving) "Saving..." else "Save Sales Tax",
                onClick = {
                    if (!canEdit) return@ActionButton
                    val basisPoints = parseTaxRateInputToBps(draftTaxRate)
                    when {
                        basisPoints == null -> taxSaveError = "Enter a valid sales tax rate such as 7.25."
                        basisPoints !in 0..10_000 -> taxSaveError = "Enter a sales tax rate between 0 and 100."
                        else -> scope.launch {
                            isSaving = true
                            taxSaveError = null
                            taxSaveMessage = null
                            try {
                                val updated = apiClient.updateDistrictSettings(
                                    districtId = selectedDistrict.id,
                                    request = UpdateDistrictSettingsRequest(
                                        defaultTaxRateBps = basisPoints,
                                        consumerApp = settings?.consumerApp,
                                    )
                                )
                                settings = updated
                                draftTaxRate = formatTaxRateInput(updated.defaultTaxRateBps)
                                onDistrictTaxRateUpdated(updated.defaultTaxRateBps)
                                taxSaveMessage = "Saved. Taxable products in ${selectedDistrict.name} now use ${formatTaxRatePercent(updated.defaultTaxRateBps)}."
                            } catch (exception: Exception) {
                                taxSaveError = exception.message ?: "Unable to save district settings."
                            } finally {
                                isSaving = false
                            }
                        }
                    }
                },
                theme = theme,
                isDisabled = isLoading || isSaving || !canEdit,
            )
        }

        SectionCard(
            title = "Consumer Runtime",
            theme = theme,
            description = "Store optional NativeUI theme JSON and one NativeUI app document JSON blob for consumer apps in this district.",
            headerActions = {
                ActionButton(
                    label = if (isLoading) "Loading..." else "Reload",
                    onClick = {
                        scope.launch {
                            loadSettings(selectedDistrict)
                        }
                    },
                    theme = theme,
                    isPrimary = false,
                    isDisabled = isLoading || isSaving || !canEdit,
                )
            },
        ) {
            loadError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            runtimeSaveError?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Error,
                )
            }

            runtimeSaveMessage?.let {
                StatusBanner(
                    message = it,
                    theme = theme,
                    tone = BannerTone.Success,
                )
            }

            themeJsonError?.let {
                StatusBanner(
                    message = "Theme JSON preview is unavailable: $it",
                    theme = theme,
                    tone = BannerTone.Info,
                )
            }

            appDocumentError?.let {
                StatusBanner(
                    message = "App document preview is unavailable: $it",
                    theme = theme,
                    tone = BannerTone.Info,
                )
            }

            appDocumentValidation?.let { validation ->
                StatusBanner(
                    message = validation.message,
                    theme = theme,
                    tone = when (validation.tone) {
                        AppDocumentValidationTone.Success -> BannerTone.Success
                        AppDocumentValidationTone.Info -> BannerTone.Info
                        AppDocumentValidationTone.Error -> BannerTone.Error
                    },
                )
            }

            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                        gap(18.px)
                    }
                }
            ) {
                P(
                    attrs = {
                        style {
                            margin(0.px)
                            property("color", theme.onSurfaceVariant)
                            property("font-size", "0.9rem")
                            property("line-height", "1.55")
                        }
                    }
                ) {
                    Text("Use the structured theme fields for the most common NativeUI roles. The app document builder below now handles page and block authoring directly, while advanced raw JSON remains available when you need it.")
                }

                FieldRow {
                    TextField(
                        theme = theme,
                        label = "Expected Tab Route IDs",
                        value = draftRequiredTabRouteIds,
                        placeholder = "home, events, wallet, account",
                        onValueChange = {
                            if (canEdit) {
                                draftRequiredTabRouteIds = it
                                runtimeSaveError = null
                                runtimeSaveMessage = null
                            }
                        },
                    )
                    TextField(
                        theme = theme,
                        label = "Home Tab Route ID",
                        value = draftHomeTabId,
                        placeholder = "home",
                        onValueChange = {
                            if (canEdit) {
                                draftHomeTabId = it
                                runtimeSaveError = null
                                runtimeSaveMessage = null
                            }
                        },
                    )
                }

                P(
                    attrs = {
                        style {
                            margin(0.px)
                            property("color", theme.onSurfaceVariant)
                            property("font-size", "0.9rem")
                            property("line-height", "1.55")
                        }
                    }
                ) {
                    Text("These IDs come from the Android tenant bundle navigation config. Admin web validates the document against them, but tab order, labels, and icons are still build-time only and are not saved here.")
                }

                commonThemeFields.chunked(2).forEach { fieldRow ->
                    FieldRow {
                        fieldRow.forEach { field ->
                            ThemeDraftField(
                                field = field,
                                currentValue = parsedThemeObject.themeValue(field.key),
                                theme = theme,
                                onValueChange = { nextValue ->
                                    if (canEdit) {
                                        draftConsumerThemeJson = updateThemeJsonField(
                                            currentJson = draftConsumerThemeJson,
                                            key = field.key,
                                            value = nextValue,
                                        )
                                        runtimeSaveError = null
                                        runtimeSaveMessage = null
                                    }
                                },
                            )
                        }
                    }
                }
            }

            TextAreaField(
                theme = theme,
                label = "Advanced Theme JSON",
                value = draftConsumerThemeJson,
                placeholder = """{"primary":"#0B5FFF","onPrimary":"#FFFFFF"}""",
                rows = 8,
                indentWithSpaces = 2,
                labelAction = {
                    EditorUtilityButton(
                        label = "Pretty JSON",
                        theme = theme,
                        isDisabled = draftConsumerThemeJson.trim().isBlank() || themeJsonError != null || !canEdit,
                        onClick = {
                            if (!canEdit) return@EditorUtilityButton
                            draftConsumerThemeJson = prettyPrintJson(draftConsumerThemeJson)
                            runtimeSaveError = null
                            runtimeSaveMessage = null
                        },
                    )
                },
                onValueChange = {
                    if (canEdit) {
                        draftConsumerThemeJson = it
                        runtimeSaveError = null
                        runtimeSaveMessage = null
                    }
                },
            )

            when (val availability = appDocumentEditorAvailability) {
                is AppDocumentEditorAvailability.Blank -> {
                    Div(
                        attrs = {
                            style {
                                display(DisplayStyle.Flex)
                                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                                gap(14.px)
                                padding(18.px)
                                borderRadius(22.px)
                                property("background", theme.surfaceContainerHighest)
                                property("border", "1px solid ${theme.outlineVariant}")
                                property("box-shadow", "inset 0 1px 0 ${theme.scrim}")
                            }
                        }
                    ) {
                        P(
                            attrs = {
                                style {
                                    margin(0.px)
                                    property("font-size", "0.88rem")
                                    property("font-weight", "700")
                                    property("letter-spacing", "0.08em")
                                    property("text-transform", "uppercase")
                                    property("color", theme.onSurfaceVariant)
                                }
                            }
                        ) {
                            Text("App Document Builder")
                        }
                        P(
                            attrs = {
                                style {
                                    margin(0.px)
                                    property("font-size", "0.96rem")
                                    property("line-height", "1.6")
                                    property("color", theme.onSurfaceVariant)
                                }
                            }
                        ) {
                            Text("No app document draft is active right now. Start with a guided document seeded from the current tab route IDs, or open the advanced JSON editor if you need to author the raw shape directly.")
                        }
                        FieldRow {
                            ActionButton(
                                label = "Create Guided App Document",
                                onClick = {
                                    if (!canEdit) return@ActionButton
                                    draftAppDocumentJson = encodeDocumentDraft(availability.suggestion)
                                    selectedPreviewScreenId = availability.suggestion.rootPageId
                                    runtimeSaveError = null
                                    runtimeSaveMessage = null
                                },
                                theme = theme,
                                isDisabled = !canEdit,
                            )
                            ActionButton(
                                label = if (showAdvancedAppDocumentJson) "Hide Advanced JSON" else "Show Advanced JSON",
                                onClick = { showAdvancedAppDocumentJson = !showAdvancedAppDocumentJson },
                                theme = theme,
                                isDisabled = false,
                                isPrimary = false,
                            )
                        }
                    }
                }

                is AppDocumentEditorAvailability.RawFallback -> {
                    StatusBanner(
                        message = availability.message,
                        theme = theme,
                        tone = BannerTone.Info,
                    )
                }

                is AppDocumentEditorAvailability.Ready -> {
                    FieldRow {
                        ActionButton(
                            label = if (showAdvancedAppDocumentJson) "Hide Advanced JSON" else "Show Advanced JSON",
                            onClick = { showAdvancedAppDocumentJson = !showAdvancedAppDocumentJson },
                            theme = theme,
                            isDisabled = false,
                            isPrimary = false,
                        )
                    }
                    NativeUiDocumentGuidedEditor(
                        draft = availability.draft,
                        selectedPageId = selectedPreviewScreenId,
                        onSelectedPageChange = { selectedPreviewScreenId = it },
                        requiredTabRouteIds = requiredTabRouteIds,
                        homeTabId = normalizedHomeTabId,
                        canEdit = canEdit,
                        theme = theme,
                        onChange = { nextDraft ->
                            if (canEdit) {
                                draftAppDocumentJson = encodeDocumentDraft(nextDraft)
                                runtimeSaveError = null
                                runtimeSaveMessage = null
                            }
                        },
                    )
                }
            }

            if (
                showAdvancedAppDocumentJson ||
                appDocumentEditorAvailability is AppDocumentEditorAvailability.RawFallback ||
                appDocumentError != null
            ) {
                TextAreaField(
                    theme = theme,
                    label = "Advanced App Document JSON",
                    value = draftAppDocumentJson,
                    placeholder = """{"id":"selu-app","version":"1.0","rootPageId":"home","pages":[{"id":"home","title":"Home","blocks":[]},{"id":"events","title":"Events","blocks":[]}]}""",
                    rows = 14,
                    indentWithSpaces = 2,
                    labelAction = {
                        EditorUtilityButton(
                            label = "Pretty JSON",
                            theme = theme,
                            isDisabled = draftAppDocumentJson.trim().isBlank() || appDocumentError != null || !canEdit,
                            onClick = {
                                if (!canEdit) return@EditorUtilityButton
                                draftAppDocumentJson = prettyPrintJson(draftAppDocumentJson)
                                runtimeSaveError = null
                                runtimeSaveMessage = null
                            },
                        )
                    },
                    onValueChange = {
                        if (canEdit) {
                            draftAppDocumentJson = it
                            runtimeSaveError = null
                            runtimeSaveMessage = null
                        }
                    },
                )
            }

            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("color", theme.onSurfaceVariant)
                        property("font-size", "0.9rem")
                        property("line-height", "1.55")
                    }
                }
            ) {
                Text("Leave either field blank to fall back to bundled app defaults. Theme JSON should match NativeUI theme role names, and the app document should be a full NativeUI document object with whatever pages, blocks, and flows you want the runtime host to render.")
            }

            ConsumerRuntimePreviewCard(
                theme = theme,
                previewTheme = resolvedPreviewTheme(
                    adminTheme = theme,
                    themeObject = parsedThemeObject,
                ),
                preview = previewModel,
                selectedScreenId = selectedPreviewScreenId,
                onScreenSelected = { selectedPreviewScreenId = it },
                themeJsonError = themeJsonError,
                appDocumentError = appDocumentError,
            )

            ActionButton(
                label = if (isSaving) "Saving..." else "Save Consumer Runtime",
                onClick = {
                    if (!canEdit) return@ActionButton
                    if (appDocumentValidation?.tone == AppDocumentValidationTone.Error) {
                        runtimeSaveError = appDocumentValidation.message
                        return@ActionButton
                    }
                    scope.launch {
                        isSaving = true
                        runtimeSaveError = null
                        runtimeSaveMessage = null
                        try {
                            val updated = apiClient.updateDistrictSettings(
                                districtId = selectedDistrict.id,
                                request = UpdateDistrictSettingsRequest(
                                    defaultTaxRateBps = settings?.defaultTaxRateBps
                                        ?: selectedDistrict.defaultTaxRateBps
                                        ?: 0,
                                    consumerApp = ConsumerAppRuntimeSettings(
                                        nativeUiThemeJson = draftConsumerThemeJson.trim().ifBlank { null },
                                        appDocumentJson = draftAppDocumentJson.trim().ifBlank { null },
                                    ).takeIf {
                                        it.nativeUiThemeJson != null || it.appDocumentJson != null
                                    },
                                )
                            )
                            settings = updated
                            draftConsumerThemeJson = updated.consumerApp?.nativeUiThemeJson.orEmpty()
                            draftAppDocumentJson = updated.consumerApp?.appDocumentJson.orEmpty()
                            runtimeSaveMessage = "Saved. Consumer apps in ${selectedDistrict.name} will use the updated runtime NativeUI theme and app document on their next refresh."
                        } catch (exception: Exception) {
                            runtimeSaveError = exception.message ?: "Unable to save consumer runtime settings."
                        } finally {
                            isSaving = false
                        }
                    }
                },
                theme = theme,
                isDisabled = isLoading || isSaving || !canEdit || appDocumentValidation?.tone == AppDocumentValidationTone.Error,
            )
        }
    }
}

@Composable
private fun EditorUtilityButton(
    label: String,
    theme: MaterialThemePalette,
    isDisabled: Boolean,
    onClick: () -> Unit,
) {
    Button(
        attrs = {
            onClick { if (!isDisabled) onClick() }
            if (isDisabled) disabled()
            style {
                padding(8.px, 12.px)
                borderRadius(999.px)
                property("cursor", if (isDisabled) "default" else "pointer")
                property("background", if (isDisabled) theme.surfaceContainerHighest else theme.primaryContainer)
                property("color", if (isDisabled) theme.onSurfaceVariant else theme.onPrimaryContainer)
                property("border", "1px solid ${theme.outlineVariant}")
                property("font-size", "0.78rem")
                property("font-weight", "700")
                property("white-space", "nowrap")
                if (isDisabled) {
                    property("opacity", "0.65")
                }
            }
        }
    ) {
        Text(label)
    }
}

@Composable
private fun ThemeDraftField(
