@Composable
private fun ConsumerRuntimePreviewCard(
    theme: MaterialThemePalette,
    previewTheme: PreviewThemePalette,
    preview: ConsumerRuntimePreviewModel,
    selectedScreenId: String?,
    onScreenSelected: (String) -> Unit,
    themeJsonError: String?,
    appDocumentError: String?,
) {
    val activeScreen = preview.screens.firstOrNull { it.id == selectedScreenId }
        ?: preview.screens.firstOrNull { it.id == preview.defaultScreenId }
        ?: preview.screens.firstOrNull()
    val previewEyebrow = activeScreen?.previewEyebrow ?: preview.fallbackEyebrow
    val previewTitle = activeScreen?.previewTitle ?: preview.fallbackTitle
    val previewBody = activeScreen?.previewBody ?: preview.fallbackBody
    val previewButtons = activeScreen?.previewButtons ?: preview.fallbackButtons

    Div(
        attrs = {
            style {
                display(DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                gap(16.px)
                padding(18.px)
                borderRadius(24.px)
                property(
                    "background",
                    "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surfaceVariant} 100%)"
                )
                property("border", "1px solid ${theme.outlineVariant}")
                property("box-shadow", "0 16px 32px ${theme.shadow}, inset 0 1px 0 ${theme.scrim}")
            }
        }
    ) {
        P(
            attrs = {
                style {
                    margin(0.px)
                    property("font-size", "0.8rem")
                    property("font-weight", "700")
                    property("letter-spacing", "0.08em")
                    property("text-transform", "uppercase")
                    property("color", theme.onSurfaceVariant)
                }
            }
        ) {
            Text("Live Preview")
        }

        FieldRow {
            PreviewSwatch("Primary", previewTheme.primary, previewTheme.onPrimary, theme)
            PreviewSwatch("Surface", previewTheme.surface, previewTheme.onSurface, theme)
            PreviewSwatch("Background", previewTheme.background, previewTheme.onBackground, theme)
        }

        if (preview.screens.isNotEmpty()) {
            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                        gap(10.px)
                    }
                }
            ) {
                P(
                    attrs = {
                        style {
                            margin(0.px)
                            property("font-size", "0.78rem")
                            property("font-weight", "700")
                            property("letter-spacing", "0.08em")
                            property("text-transform", "uppercase")
                            property("color", theme.onSurfaceVariant)
                        }
                    }
                ) {
                    Text("App Screens")
                }

                FieldRow {
                    preview.screens.forEach { screen ->
                        PreviewScreenCard(
                            screen = screen,
                            isSelected = screen.id == activeScreen?.id,
                            onClick = { onScreenSelected(screen.id) },
                            previewTheme = previewTheme,
                            theme = theme,
                        )
                    }
                }
            }
        }

        Div(
            attrs = {
                style {
                    padding(20.px)
                    borderRadius(24.px)
                    property("background", previewTheme.background)
                    property("color", previewTheme.onBackground)
                    property("border", "1px solid ${previewTheme.outline}")
                    property("box-shadow", "inset 0 1px 0 rgba(255,255,255,0.24)")
                }
            }
        ) {
            Div(
                attrs = {
                    style {
                        display(DisplayStyle.Flex)
                        property("justify-content", "space-between")
                        property("align-items", "center")
                        gap(12.px)
                    }
                }
            ) {
                Div {
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "0.78rem")
                                property("font-weight", "700")
                                property("letter-spacing", "0.08em")
                                property("text-transform", "uppercase")
                                property("color", previewTheme.primary)
                            }
                        }
                    ) {
                        Text(previewEyebrow)
                    }
                    P(
                        attrs = {
                            style {
                                margin(0.px)
                                property("font-size", "1.35rem")
                                property("font-weight", "700")
                                property("color", previewTheme.onBackground)
                            }
                        }
                    ) {
                        Text(previewTitle)
                    }
                }
                previewTheme.logoUrl?.let { logoUrl ->
                    Div(
                        attrs = {
                            style {
                                padding(8.px, 12.px)
                                borderRadius(999.px)
                                property("background", previewTheme.surfaceVariant)
                                property("color", previewTheme.onSurfaceVariant)
                                property("font-size", "0.78rem")
                                property("font-weight", "600")
                                property("max-width", "240px")
                                property("overflow", "hidden")
                                property("text-overflow", "ellipsis")
                                property("white-space", "nowrap")
                            }
                        }
                    ) {
                        Text("Logo: $logoUrl")
                    }
                }
            }

            Div(
                attrs = {
                    style {
                        property("margin-top", "16px")
                        padding(18.px)
                        borderRadius(22.px)
                        property("background", previewTheme.surface)
                        property("color", previewTheme.onSurface)
                        property("border", "1px solid ${previewTheme.outline}")
                    }
                }
            ) {
                P(
                    attrs = {
                        style {
                            margin(0.px)
                            property("font-size", "1.1rem")
                            property("font-weight", "700")
                        }
                    }
                ) {
                    Text(previewTitle)
                }
                P(
                    attrs = {
                        style {
                            property("margin-top", "10px")
                            margin(0.px)
                            property("font-size", "0.96rem")
                            property("line-height", "1.6")
                            property("color", previewTheme.onSurfaceVariant)
                        }
                    }
                ) {
                    Text(previewBody)
                }
                Div(
                    attrs = {
                        style {
                            display(DisplayStyle.Flex)
                            gap(10.px)
                            property("flex-wrap", "wrap")
                            property("margin-top", "16px")
                        }
                    }
                ) {
                    previewButtons.forEachIndexed { index, label ->
                        Div(
                            attrs = {
                                style {
                                    padding(12.px, 16.px)
                                    borderRadius(14.px)
                                    property(
                                        "background",
                                        if (index == 0) previewTheme.primary else previewTheme.surfaceVariant
                                    )
                                    property(
                                        "color",
                                        if (index == 0) previewTheme.onPrimary else previewTheme.onSurface
                                    )
                                    property(
                                        "border",
                                        if (index == 0) {
                                            "1px solid ${previewTheme.primary}"
                                        } else {
                                            "1px solid ${previewTheme.outline}"
                                        }
                                    )
                                    property("font-size", "0.92rem")
                                    property("font-weight", "700")
                                }
                            }
                        ) {
                            Text(label)
                        }
                    }
                }
            }
        }

        if (themeJsonError == null && appDocumentError == null) {
            P(
                attrs = {
                    style {
                        margin(0.px)
                        property("font-size", "0.88rem")
                        property("color", theme.onSurfaceVariant)
                        property("line-height", "1.5")
                    }
                }
            ) {
                Text("Preview updates from the current draft. Invalid color tokens fall back to the admin palette in this preview, while the saved JSON remains unchanged until you save. Select any screen card to swap the preview to that page's content.")
            }
        }
    }
}

