private data class PreviewThemePalette(
    val primary: String,
    val onPrimary: String,
    val background: String,
    val onBackground: String,
    val surface: String,
    val onSurface: String,
    val surfaceVariant: String,
    val onSurfaceVariant: String,
    val outline: String,
    val logoUrl: String?,
)

private fun resolvedPreviewTheme(
    adminTheme: MaterialThemePalette,
    themeObject: JsonObject?,
): PreviewThemePalette =
    PreviewThemePalette(
        primary = themeObject.cssColor("primary") ?: adminTheme.primary,
        onPrimary = themeObject.cssColor("onPrimary") ?: adminTheme.onPrimary,
        background = themeObject.cssColor("background") ?: adminTheme.surface,
        onBackground = themeObject.cssColor("onBackground") ?: adminTheme.onSurface,
        surface = themeObject.cssColor("surface") ?: adminTheme.surfaceContainerHighest,
        onSurface = themeObject.cssColor("onSurface") ?: adminTheme.onSurface,
        surfaceVariant = themeObject.cssColor("surfaceVariant") ?: adminTheme.surfaceVariant,
        onSurfaceVariant = themeObject.cssColor("onSurfaceVariant") ?: adminTheme.onSurfaceVariant,
        outline = themeObject.cssColor("outline") ?: adminTheme.outline,
        logoUrl = themeObject.themeValue("logoUrl").ifBlank { null },
    )

private fun parseJsonObjectOrNull(rawJson: String): JsonObject? {
    val candidate = rawJson.trim().ifBlank { return null }
    return runCatching { runtimeJson.parseToJsonElement(candidate).jsonObject }.getOrNull()
}

private fun prettyPrintJson(rawJson: String): String {
    val candidate = rawJson.trim()
    if (candidate.isBlank()) return ""
    val parsed = runtimeJson.parseToJsonElement(candidate)
    return runtimeJson.encodeToString(JsonElement.serializer(), parsed)
}

private fun jsonObjectError(rawJson: String): String? {
    val candidate = rawJson.trim()
    if (candidate.isBlank()) return null
    return runCatching {
        runtimeJson.parseToJsonElement(candidate).jsonObject
        null
    }.getOrElse { "Enter a valid JSON object." }
}

private fun updateThemeJsonField(
    currentJson: String,
    key: String,
    value: String,
): String {
    val nextValues = (parseJsonObjectOrNull(currentJson)?.toMutableMap() ?: linkedMapOf()).also { values ->
        val normalized = value.trim()
        if (normalized.isBlank()) {
            values.remove(key)
        } else {
            values[key] = JsonPrimitive(normalized)
        }
    }

    if (nextValues.isEmpty()) {
        return ""
    }

    return runtimeJson.encodeToString(JsonObject(nextValues))
}

private fun JsonObject?.themeValue(key: String): String =
    this?.get(key)?.jsonPrimitive?.contentOrNull.orEmpty()

private fun JsonObject?.cssColor(key: String): String? =
    this?.themeValue(key)?.let(::nativeUiColorToCss)

private fun nativeUiColorToCss(rawValue: String): String? {
    val normalized = rawValue.trim().removePrefix("#")
    return when {
        normalized.length == 6 && normalized.matches(Regex("[0-9A-Fa-f]{6}")) -> "#$normalized"
        normalized.length == 8 && normalized.matches(Regex("[0-9A-Fa-f]{8}")) -> {
            val alpha = normalized.substring(0, 2).toIntOrNull(16) ?: return null
            val red = normalized.substring(2, 4).toIntOrNull(16) ?: return null
            val green = normalized.substring(4, 6).toIntOrNull(16) ?: return null
            val blue = normalized.substring(6, 8).toIntOrNull(16) ?: return null
            "rgba($red, $green, $blue, ${alpha.toDouble() / 255.0})"
        }
        else -> null
    }
}

private fun buildConsumerRuntimePreviewModel(rawDocumentJson: String): ConsumerRuntimePreviewModel {
    val jsonObject = parseJsonObjectOrNull(rawDocumentJson)
    val rootPageId = jsonObject?.get("rootPageId")?.jsonPrimitive?.contentOrNull
    val pages = jsonObject
        ?.get("pages")
        ?.jsonArray
        ?.mapNotNull { runCatching { it.jsonObject }.getOrNull() }
        .orEmpty()
    val pageObject = pages.firstOrNull { page ->
        page["id"]?.jsonPrimitive?.contentOrNull == rootPageId
    } ?: pages.firstOrNull()
    val selectedPageId = pageObject?.get("id")?.jsonPrimitive?.contentOrNull
    val flattenedBlocks = pageObject
        ?.get("blocks")
        ?.jsonArray
        ?.flatMap(::flattenBlocks)
        .orEmpty()

    val eyebrow = flattenedBlocks.firstText("Label")
        ?: pageObject?.get("title")?.jsonPrimitive?.contentOrNull
        ?: selectedPageId
        ?: "Runtime App"
    val title = flattenedBlocks.firstText("Title")
        ?: pageObject?.get("title")?.jsonPrimitive?.contentOrNull
        ?: if (pages.size > 1) "Runtime App Preview" else "Runtime Screen Preview"
    val body = flattenedBlocks.firstText("Body")
        ?: buildPreviewBody(pageId = selectedPageId, isRoot = selectedPageId == rootPageId, pageCount = pages.size)
    val buttons = flattenedBlocks.buttonLabels().ifEmpty {
        listOf("Primary Action", "Secondary Action")
    }

    return ConsumerRuntimePreviewModel(
        defaultScreenId = selectedPageId,
        fallbackEyebrow = eyebrow,
        fallbackTitle = title,
        fallbackBody = body,
        fallbackButtons = buttons,
        screens = pages.map { page ->
            val pageId = page["id"]?.jsonPrimitive?.contentOrNull ?: "untitled"
            val pageTitle = page["title"]?.jsonPrimitive?.contentOrNull ?: pageId
            val blockCount = page["blocks"]?.jsonArray?.size ?: 0
            val pageBlocks = page["blocks"]
                ?.jsonArray
                ?.flatMap(::flattenBlocks)
                .orEmpty()
            ConsumerRuntimeScreenPreview(
                id = pageId,
                label = pageTitle,
                blockCount = blockCount,
                isRoot = pageId == rootPageId,
                previewEyebrow = pageBlocks.firstText("Label") ?: pageTitle,
                previewTitle = pageBlocks.firstText("Title") ?: pageTitle,
                previewBody = pageBlocks.firstText("Body")
                    ?: buildPreviewBody(pageId = pageId, isRoot = pageId == rootPageId, pageCount = pages.size),
                previewButtons = pageBlocks.buttonLabels().ifEmpty {
                    listOf("Primary Action", "Secondary Action")
                },
            )
        },
    )
}

private fun buildPreviewBody(
    pageId: String?,
    isRoot: Boolean,
    pageCount: Int,
): String =
    when {
        pageCount > 1 && isRoot && pageId != null -> "Previewing the root screen \"$pageId\" from a $pageCount-screen NativeUI app document."
        pageCount > 1 && pageId != null -> "Previewing screen \"$pageId\" from a $pageCount-screen NativeUI app document."
        pageCount > 1 -> "Previewing the first screen from a $pageCount-screen NativeUI app document."
        pageCount == 1 && pageId != null -> "Previewing screen \"$pageId\" before saving."
        pageCount == 1 -> "Previewing the current NativeUI screen draft before saving."
        else -> "Preview the district's NativeUI app content here before saving."
    }

private fun parseRouteIds(rawValue: String): List<String> =
    rawValue
        .split(",")
        .map { it.trim() }
        .filter { it.isNotEmpty() }
        .distinct()

private fun validateAppDocument(
    rawDocumentJson: String,
    documentJsonError: String?,
    requiredTabRouteIds: List<String>,
    homeTabId: String,
): AppDocumentValidation? {
    val candidate = rawDocumentJson.trim()
    if (candidate.isBlank() || documentJsonError != null) {
        return null
    }
    if (requiredTabRouteIds.isEmpty()) {
        return AppDocumentValidation(
            tone = AppDocumentValidationTone.Error,
            message = "Enter at least one expected tab route ID from the Android tenant bundle before saving the app document.",
        )
    }
    if (homeTabId.isBlank()) {
        return AppDocumentValidation(
            tone = AppDocumentValidationTone.Error,
            message = "Enter the Android tenant bundle home tab route ID before saving the app document.",
        )
    }
    if (homeTabId !in requiredTabRouteIds) {
        return AppDocumentValidation(
            tone = AppDocumentValidationTone.Error,
            message = "Home tab route ID \"$homeTabId\" must match one of the expected tab route IDs.",
        )
    }

    val documentObject = parseJsonObjectOrNull(candidate) ?: return null
    val rootPageId = documentObject["rootPageId"]?.jsonPrimitive?.contentOrNull?.trim().orEmpty()
    val pageIds = documentObject["pages"]
        ?.jsonArray
        ?.mapNotNull { runCatching { it.jsonObject }.getOrNull() }
        ?.mapNotNull { page -> page["id"]?.jsonPrimitive?.contentOrNull?.trim()?.ifBlank { null } }
        .orEmpty()
        .distinct()

    if (rootPageId.isBlank()) {
        return AppDocumentValidation(
            tone = AppDocumentValidationTone.Error,
            message = "App document JSON must include a non-blank rootPageId.",
        )
    }
    if (pageIds.isEmpty()) {
        return AppDocumentValidation(
            tone = AppDocumentValidationTone.Error,
            message = "App document JSON must include at least one page.",
        )
    }
    if (rootPageId !in pageIds) {
        return AppDocumentValidation(
            tone = AppDocumentValidationTone.Error,
            message = "rootPageId \"$rootPageId\" does not match any page id in the document.",
        )
    }

    val missingTabRouteIds = requiredTabRouteIds.filterNot(pageIds::contains)
    return if (missingTabRouteIds.isEmpty()) {
        AppDocumentValidation(
            tone = AppDocumentValidationTone.Success,
            message = "Ready for full app replacement. The document includes all expected tab root pages: ${requiredTabRouteIds.joinToString(", ")}.",
        )
    } else {
        AppDocumentValidation(
            tone = AppDocumentValidationTone.Info,
            message = "Missing tab root pages: ${missingTabRouteIds.joinToString(", ")}. Selu Consumer Android will treat this as a legacy home-tab override instead of a full app document replacement and keep the bundled pages for the other tabs.",
        )
    }
}

private fun flattenBlocks(element: kotlinx.serialization.json.JsonElement): List<JsonObject> {
    val block = runCatching { element.jsonObject }.getOrNull() ?: return emptyList()
    val children = block["blocks"]
        ?.let { childElement ->
            runCatching { childElement.jsonArray.flatMap(::flattenBlocks) }.getOrElse { emptyList() }
        }
        .orEmpty()
    return listOf(block) + children
}

private fun List<JsonObject>.firstText(variant: String): String? =
    firstOrNull { block ->
        block["type"]?.jsonPrimitive?.contentOrNull == "text" &&
            block["variant"]?.jsonPrimitive?.contentOrNull == variant
    }?.get("text")?.jsonPrimitive?.contentOrNull

private fun List<JsonObject>.buttonLabels(): List<String> =
    mapNotNull { block ->
        if (block["type"]?.jsonPrimitive?.contentOrNull == "button") {
            block["label"]?.jsonPrimitive?.contentOrNull
        } else {
            null
        }
    }
