package com.kanati.shared.ticket

import com.kanati.shared.commerce.SaleResponse
import com.kanati.shared.commerce.TerminalPaymentSessionResponse
import kotlinx.serialization.Serializable

@Serializable
enum class TicketEntitlementType {
    CONCESSION_CREDIT,
    FREE_ITEM_PER_EVENT,
    SEASON_PASS,
    MERCH_CREDIT
}

@Serializable
data class TicketEntitlementDto(
    val type: TicketEntitlementType,
    val label: String,
    val amount: Int? = null,
    val quantity: Int? = null,
)

@Serializable
enum class TicketStatus {
    VALID,
    UNUSED,
    INVALID,
    USED,
    ADMITTED,
    VOID,
    RELEASED,
}

@Serializable
enum class PaperTicketBatchStatus {
    ACTIVE,
    RELEASED,
    CLOSED,
}

@Serializable
data class TicketDto(
    val id: String,
    val eventId: String,
    val districtId: String,
    val schoolId: String = "",
    val ticketTierId: String,
    val ticketTierName: String,
    val ticketTierPriceAmount: Int,
    val ticketCode: String,
    val status: TicketStatus,
    val paperBatchId: String? = null,
    val entitlements: List<TicketEntitlementDto> = emptyList(),
    val holderName: String?,
    val createdAt: String,
    val usedAt: String?,
)

@Serializable
data class IssueTicketRequest(
    val eventId: String,
    val districtId: String,
    val schoolId: String = "",
    val ticketTierId: String,
    val holderName: String? = null,
)

@Serializable
data class CreatePaperTicketBatchRequest(
    val eventId: String,
    val districtId: String,
    val schoolId: String = "",
    val ticketTierId: String,
    val quantity: Int,
)

@Serializable
data class SellTicketRequest(
    val eventId: String,
    val districtId: String,
    val schoolId: String = "",
    val ticketTierId: String,
    val paymentMethod: String,
    val paymentIntentId: String? = null,
    val holderName: String? = null,
)

@Serializable
data class StartTerminalTicketSalePaymentRequest(
    val sale: SellTicketRequest,
    val terminalReaderId: String,
)

@Serializable
data class TicketCheckInRequest(
    val ticketCode: String,
)

@Serializable
data class SellTicketResponse(
    val sale: SaleResponse,
    val ticket: TicketDto,
)

@Serializable
data class RecoverTerminalTicketPaymentResponse(
    val session: TerminalPaymentSessionResponse,
    val sale: SaleResponse? = null,
    val ticket: TicketDto? = null,
)

@Serializable
data class CreatePaperTicketBatchResponse(
    val batch: PaperTicketBatchDto,
    val tickets: List<TicketDto>,
)

@Serializable
data class EventIssuedTicketsResponse(
    val eventId: String,
    val tickets: List<TicketDto>,
)

@Serializable
data class PaperTicketBatchDto(
    val id: String,
    val eventId: String,
    val districtId: String,
    val schoolId: String = "",
    val ticketTierId: String,
    val ticketTierName: String,
    val reservedQuantity: Int,
    val admittedQuantity: Int,
    val releasedQuantity: Int,
    val remainingQuantity: Int,
    val status: PaperTicketBatchStatus,
    val createdAt: String,
)

@Serializable
data class EventPaperTicketBatchesResponse(
    val eventId: String,
    val batches: List<PaperTicketBatchDto>,
)

@Serializable
data class ReleasePaperTicketBatchRequest(
    val releaseQuantity: Int,
)

@Serializable
data class TicketCheckInResponse(
    val success: Boolean,
    val status: TicketStatus,
    val message: String,
    val ticket: TicketDto? = null,
)
